// src/domain/order.ts — DOMAIN layer (should be pure: no dependency on infra).
// VIOLATION: the domain entity imports the infrastructure repository, inverting the
// correct dependency direction (infra should depend on domain, never the reverse).
import { persist } from "../infra/repository.ts";

export interface Order {
  id: string;
  total: number;
}

export function checkout(order: Order): void {
  // domain logic reaching straight into infrastructure
  persist(order);
}

// src/infra/repository.ts — INFRASTRUCTURE layer.
// Imports the domain type (this direction is fine on its own), but combined with
// order.ts importing persist() back, it closes a domain↔infra dependency cycle.
import type { Order } from "../domain/order.ts";

const store: Order[] = [];

export function persist(order: Order): void {
  store.push(order);
}

// src/domain/order.ts — DOMAIN layer: pure. Imports nothing from infra or app.
export interface Order {
  id: string;
  total: number;
}

export function isLarge(order: Order): boolean {
  return order.total > 1000;
}

// src/infra/repository.ts — INFRASTRUCTURE layer: depends INWARD on the domain only
// (correct direction). Never imported by the domain.
import type { Order } from "../domain/order.ts";

const store: Order[] = [];

export function persist(order: Order): void {
  store.push(order);
}

// src/app/checkout-service.ts — APPLICATION layer: composes domain + infra.
import { type Order, isLarge } from "../domain/order.ts";
import { persist } from "../infra/repository.ts";

export function checkout(order: Order): void {
  if (isLarge(order)) {
    // ... apply large-order policy
  }
  persist(order);
}
